let unmutedbutton = document.createElement("span");
let getoverlay = document
  .getElementsByClassName("vjs-unmute-overlay")[0];
// var unmutedbutton = document.querySelector('#foo .bar');
let translated = "UNMUTE";
let mute_translated = "MUTE";
unmutedbutton.id = "ctrl-btn"
unmutedbutton.textContent = translated;
unmutedbutton.classList.add("vjs-unmute");
unmutedbutton.setAttribute("style", "color:white;");
unmutedbutton.style.opacity = 0;
unmutedbutton.style.display = "none";

getoverlay.appendChild(unmutedbutton);
let player = $("#audio");
// +++ Add button's event listener +++
let stream = $('#stream');
function setUnmuteLocation() {
    let tranform = stream.style.transform;
    let reg = /[0-9.]+px/g;
    let left = reg.exec(tranform);
    let top = reg.exec(tranform);
    unmutedbutton.style.left = left;
    unmutedbutton.style.top = top;
    unmutedbutton.style.opacity = 0.9;
    setTimeout(function(){
        unmutedbutton.style.opacity = 0;
      }, 3000);
};

stream.onclick = function(e) {
    let tranform = stream.style.transform;
    let reg = /[0-9.]+px/g;
    let left = reg.exec(tranform);
    let top = reg.exec(tranform);
    unmutedbutton.style.left = left;
    unmutedbutton.style.top = top;
};

unmutedbutton.addEventListener("click", function (e) {
    if (unmutedbutton.style.opacity != 0){
        if(player.muted){
            player.play();
            player.muted = false;
            unmutedbutton.textContent = mute_translated;
            unmutedbutton.className = "vjs-mute"
            //player.volume = volumeLevel;
            //e.stopPropagation();
          }else{
            player.muted = true;
            unmutedbutton.textContent = translated;
            unmutedbutton.className = "vjs-unmute"
            //e.stopPropagation();
          }
          setTimeout(function(){
            unmutedbutton.style.opacity = 0;
            }, 1000);
    }else{
        unmutedbutton.style.opacity = 0.9;
        setTimeout(function(){
            unmutedbutton.style.opacity = 0;
            }, 3000);
    }

});

const msgHandler = {
    setFullscreenSize(data) {
        gestureBuilder.setFullscreenSize(data.width, data.height)
        setUnmuteLocation()
    },
    changeVideoSize(data) {
        ws.ws.close()
        setTimeout(function(){
           location.reload()  //reload when phone orientation changed
           }, 1000);
    },
    // 收到对方发给我的candidate
    addIceCandidate (data) {
        console.log('recv remote nat candidate', data);
        let v={};
        Object.assign(v, {candidate: data.sdp}, {sdpMLineIndex: data.sdpMLineIndex}, {sdpMid: data.sdpMid});

        currentChat.addCandidate(v);
    },
    // 收到对方的offer
    setSessionDescription (data) {
        console.log('setSessionDescription', data);
        let offer = new RTCSessionDescription();
        offer.type = 'offer';
        offer.sdp = data;
        //let offer = data.desc;
        currentChat.answer(offer);
        unmutedbutton.style.display = "block";
    },
    // 收到对方的answer
    answer (data) {
        //let offer = data.desc;
        currentChat.onRecvAnswer(data);
    },
    handlerError(data) {
        //TODO: display based on error data
    }
}
ws.setMsgHandler(msgHandler)
ws.onopen = async function() {
    logEvent(analytics, 'ws_onopen', {});
    //sleep(5000);
    // if(gestureBuilder.phoneWidth == 0 || gestureBuilder.phoneHeight == 0){
        console.log("devicePixelRatio = " + window.devicePixelRatio)
        let devicePixelRatio = 2
        ws.sendData({
            action: 'requestFullscreenSize',
            value: {
                browserWidth: window.innerWidth * devicePixelRatio,
                browserHeight: window.innerHeight * devicePixelRatio
            }
        });
    // }
    currentChat && currentChat.closeConnection();
    let chat = new Chat(ws, $("#audio"), null, null, true);

    currentChat = chat;
    chat.initConnect();
    chat.ring();
}
